  1→//! Coverage metrics for concolic exploration results.
  2→//!
  3→//! After exploration, reports what percentage of discovered branches were found
  4→//! by each method (Z3 solving, random/boundary generation, user-provided inputs)
  5→//! and what fraction of branch conditions the frontend expressed as symbolic
  6→//! expressions vs opaque unknowns.
  7→
  8→use std::collections::{HashMap, HashSet};
  9→
 10→use serde::{Deserialize, Serialize};
 11→
 12→use crate::execution_record::SymConstraint;
 13→use crate::explorer::ObservationOutput;
 14→use crate::orchestrator::ExploreResult;
 15→use crate::protocol::{BranchInfo, ExecuteResult, FunctionAnalysis};
 16→
 17→/// How a branch was discovered during exploration.
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 19→#[serde(rename_all = "snake_case")]
 20→pub enum DiscoveryMethod {
 21→    /// Found by Z3 constraint solving (negating a path constraint).
 22→    Z3,
 23→    /// Found by random or boundary input generation.
 24→    Random,
 25→    /// Found via user-provided inputs.
 26→    UserProvided,
 27→    /// Found by parameter drilling on a stalled frontier.
 28→    Drilled,
 29→}
 30→
 31→/// Percentage breakdown of discovery methods.
 32→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 33→pub struct MethodPercentages {
 34→    /// Percentage of branches found by Z3 solving.
 35→    pub z3_pct: f64,
 36→    /// Percentage of branches found by random/boundary generation.
 37→    pub random_pct: f64,
 38→    /// Percentage of branches found by user-provided inputs.
 39→    pub user_provided_pct: f64,
 40→    /// Percentage of branches still uncovered.
 41→    pub uncovered_pct: f64,
 42→}
 43→
 44→/// Coverage metrics summarizing how effective the concolic approach was.
 45→#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
 46→pub struct CoverageMetrics {
 47→    /// Total number of branch points in the function.
 48→    pub total_branches: usize,
 49→    /// Branches discovered by Z3 constraint solving.
 50→    pub z3_solved: usize,
 51→    /// Branches discovered by random/boundary generation.
 52→    pub random_found: usize,
 53→    /// Branches discovered via user-provided inputs.
 54→    pub user_provided: usize,
 55→    /// Branches that remain uncovered.
 56→    pub uncovered: usize,
 57→    /// Number of branch constraints expressed as SymExpr (solvable by Z3).
 58→    pub symexpr_count: usize,
 59→    /// Number of branch constraints that were Unknown (opaque to solver).
 60→    pub unknown_count: usize,
 61→}
 62→
 63→impl CoverageMetrics {
 64→    /// Compute percentage breakdown by discovery method.
 65→    ///
 66→    /// Returns zero percentages when there are no branches (avoids division by zero).
 67→    pub fn percentages(&self) -> MethodPercentages {
 68→        if self.total_branches == 0 {
 69→            return MethodPercentages {
 70→                z3_pct: 0.0,
 71→                random_pct: 0.0,
 72→                user_provided_pct: 0.0,
 73→                uncovered_pct: 0.0,
 74→            };
 75→        }
 76→
 77→        let total = self.total_branches as f64;
 78→        MethodPercentages {
 79→            z3_pct: self.z3_solved as f64 / total * 100.0,
 80→            random_pct: self.random_found as f64 / total * 100.0,
 81→            user_provided_pct: self.user_provided as f64 / total * 100.0,
 82→            uncovered_pct: self.uncovered as f64 / total * 100.0,
 83→        }
 84→    }
 85→
 86→    /// Symbolic expression coverage ratio: what fraction of branch conditions
 87→    /// the frontend could express as SymExpr (vs Unknown).
 88→    ///
 89→    /// Returns 0.0 if there are no constraints at all.
 90→    pub fn symexpr_ratio(&self) -> f64 {
 91→        let total = self.symexpr_count + self.unknown_count;
 92→        if total == 0 {
 93→            return 0.0;
 94→        }
 95→        self.symexpr_count as f64 / total as f64
 96→    }
 97→
 98→    /// Build metrics from a list of per-branch discovery results and constraints.
 99→    ///
100→    /// `discoveries` maps each covered branch to the method that first found it.
101→    /// `total_branches` is the total number of branch points (from static analysis).
102→    /// `constraints` is the set of all constraints observed across executions.
103→    pub fn from_exploration(
104→        total_branches: usize,
105→        discoveries: &[(u32, DiscoveryMethod)],
106→        constraints: &[SymConstraint],
107→    ) -> Self {
108→        let mut z3_solved = 0usize;
109→        let mut random_found = 0usize;
110→        let mut user_provided = 0usize;
111→
112→        for (_, method) in discoveries {
113→            match method {
114→                DiscoveryMethod::Z3 => z3_solved += 1,
115→                DiscoveryMethod::Random | DiscoveryMethod::Drilled => random_found += 1,
116→                DiscoveryMethod::UserProvided => user_provided += 1,
117→            }
118→        }
119→
120→        let covered = z3_solved + random_found + user_provided;
121→        let uncovered = total_branches.saturating_sub(covered);
122→
123→        let mut symexpr_count = 0usize;
124→        let mut unknown_count = 0usize;
125→
126→        for constraint in constraints {
127→            match constraint {
128→                SymConstraint::Expr { .. } => symexpr_count += 1,
129→                SymConstraint::Unknown { .. } => unknown_count += 1,
130→            }
131→        }
132→
133→        Self {
134→            total_branches,
135→            z3_solved,
136→            random_found,
137→            user_provided,
138→            uncovered,
139→            symexpr_count,
140→            unknown_count,
141→        }
142→    }
143→
144→    /// Additively merge `other` into `self`.
145→    ///
146→    /// Each counter is summed. The caller must ensure no double-counting
147→    /// (e.g., each function appears in exactly one batch).
148→    pub fn merge(&mut self, other: &CoverageMetrics) {
149→        self.total_branches += other.total_branches;
150→        self.z3_solved += other.z3_solved;

  1→//! Behavior clustering: group execution records by branch path.
  2→//!
  3→//! Two executions with the same sequence of branch decisions (same branch IDs,
  4→//! same taken/not-taken outcomes) belong to the same cluster. Each cluster
  5→//! tracks statistics: specimen count, input value ranges, and output value ranges.
  6→
  7→use std::collections::HashMap;
  8→
  9→use serde::{Deserialize, Serialize};
 10→
 11→use crate::execution_record::{BranchDecision, ExecutionRecord};
 12→
 13→/// A compact representation of a branch path used as a clustering key.
 14→///
 15→/// Each entry is `(branch_id, taken)` — the sequence of branch decisions
 16→/// in execution order.
 17→pub type BranchPathKey = Vec<(u32, bool)>;
 18→
 19→/// Extract the clustering key from a sequence of branch decisions.
 20→fn branch_path_key(decisions: &[BranchDecision]) -> BranchPathKey {
 21→    decisions
 22→        .iter()
 23→        .map(|d| (d.branch_id, d.taken))
 24→        .collect()
 25→}
 26→
 27→/// Observed range for a JSON value dimension (min and max as JSON values).
 28→///
 29→/// For numeric values, min/max reflect the numeric range. For non-numeric
 30→/// values, min/max are the first and last values seen (lexicographic on
 31→/// the JSON serialization).
 32→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 33→pub struct ValueRange {
 34→    pub min: serde_json::Value,
 35→    pub max: serde_json::Value,
 36→    pub distinct_count: usize,
 37→}
 38→
 39→/// Statistics for a single behavior cluster.
 40→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 41→pub struct ClusterStats {
 42→    /// Number of execution records in this cluster.
 43→    pub specimen_count: usize,
 44→    /// Range of each input parameter across all specimens.
 45→    /// Index corresponds to the parameter position.
 46→    pub input_ranges: Vec<ValueRange>,
 47→    /// Range of the output (return value) across all specimens.
 48→    /// `None` if all specimens threw errors (no return values).
 49→    pub output_range: Option<ValueRange>,
 50→}
 51→
 52→/// A group of execution records that share the same branch path.
 53→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 54→pub struct BehaviorCluster {
 55→    /// The branch path shared by all records in this cluster.
 56→    pub branch_path: BranchPathKey,
 57→    /// Human-readable label, e.g. "TF" for a 2-branch path (taken, not-taken).
 58→    pub label: String,
 59→    /// Statistics computed from the records in this cluster.
 60→    pub stats: ClusterStats,
 61→    /// Indices into the original records slice for the specimens in this cluster.
 62→    pub record_indices: Vec<usize>,
 63→}
 64→
 65→/// Result of clustering a set of execution records.
 66→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 67→pub struct ClusteringResult {
 68→    pub function_id: String,
 69→    pub total_records: usize,
 70→    pub clusters: Vec<BehaviorCluster>,
 71→}
 72→
 73→/// Compare two JSON values for ordering.
 74→///
 75→/// Numeric values are compared numerically. All other values are compared
 76→/// by their JSON serialization (which gives a stable, deterministic order).
 77→fn json_cmp(a: &serde_json::Value, b: &serde_json::Value) -> std::cmp::Ordering {
 78→    match (a.as_f64(), b.as_f64()) {
 79→        (Some(fa), Some(fb)) => fa.partial_cmp(&fb).unwrap_or(std::cmp::Ordering::Equal),
 80→        _ => {
 81→            let sa = serde_json::to_string(a).unwrap_or_default();
 82→            let sb = serde_json::to_string(b).unwrap_or_default();
 83→            sa.cmp(&sb)
 84→        }
 85→    }
 86→}
 87→
 88→/// Compute the value range for a set of JSON values.
 89→fn compute_value_range(values: &[&serde_json::Value]) -> Option<ValueRange> {
 90→    if values.is_empty() {
 91→        return None;
 92→    }
 93→
 94→    let mut sorted: Vec<&serde_json::Value> = values.to_vec();
 95→    sorted.sort_by(|a, b| json_cmp(a, b));
 96→
 97→    // Count distinct values
 98→    let mut distinct = 1;
 99→    for window in sorted.windows(2) {
100→        if window[0] != window[1] {
101→            distinct += 1;
102→        }
103→    }
104→
105→    Some(ValueRange {
106→        min: sorted[0].clone(),
107→        max: sorted[sorted.len() - 1].clone(),
108→        distinct_count: distinct,
109→    })
110→}
111→
112→/// Build a label from a branch path key.
113→///
114→/// Each decision is "T" (taken) or "F" (not-taken), concatenated in order.
115→/// For example, `[(0, true), (1, false)]` becomes `"TF"`.
116→fn path_label(key: &BranchPathKey) -> String {
117→    key.iter()
118→        .map(|(_, taken)| if *taken { 'T' } else { 'F' })
119→        .collect()
120→}
121→
122→/// Compute cluster statistics from a set of execution records.
123→fn compute_stats(records: &[&ExecutionRecord]) -> ClusterStats {
124→    let specimen_count = records.len();
125→
126→    // Determine the maximum number of parameters across all records.
127→    let max_params = records.iter().map(|r| r.parameters.len()).max().unwrap_or(0);
128→
129→    let mut input_ranges = Vec::with_capacity(max_params);
130→    for i in 0..max_params {
131→        let values: Vec<&serde_json::Value> = records
132→            .iter()
133→            .filter_map(|r| r.parameters.get(i))
134→            .collect();
135→        if let Some(range) = compute_value_range(&values) {
136→            input_ranges.push(range);
137→        }
138→    }
139→
140→    let return_values: Vec<&serde_json::Value> = records
141→        .iter()
142→        .filter_map(|r| r.return_value.as_ref())
143→        .collect();
144→    let output_range = compute_value_range(&return_values);
145→
146→    ClusterStats {
147→        specimen_count,
148→        input_ranges,
149→        output_range,
150→    }

  1→//! Branch-distance fitness function for genetic search.
  2→//!
  3→//! Scores an [`ExecuteResult`] on four axes — branch coverage, proximity
  4→//! to uncovered target branches, unknown-branch exploration bonus, and
  5→//! path novelty — and combines them into a single 0.0–1.0 fitness value.
  6→
  7→use std::collections::HashSet;
  8→
  9→use crate::execution_record::{BranchDecision, SymConstraint};
 10→use crate::orchestrator::hash_branch_path;
 11→use crate::protocol::ExecuteResult;
 12→use crate::sym_expr::{BinOpKind, ConstValue, SymExpr};
 13→
 14→/// Weights for combining the four fitness components.
 15→///
 16→/// Defaults: coverage 0.30, proximity 0.40, unknown_bonus 0.10, novelty 0.20.
 17→#[derive(Debug, Clone)]
 18→pub struct FitnessWeights {
 19→    pub coverage: f64,
 20→    pub proximity: f64,
 21→    pub unknown_bonus: f64,
 22→    pub novelty: f64,
 23→}
 24→
 25→impl Default for FitnessWeights {
 26→    fn default() -> Self {
 27→        Self {
 28→            coverage: 0.30,
 29→            proximity: 0.40,
 30→            unknown_bonus: 0.10,
 31→            novelty: 0.20,
 32→        }
 33→    }
 34→}
 35→
 36→/// Breakdown of the four fitness components before weighting.
 37→#[derive(Debug, Clone)]
 38→pub struct FitnessBreakdown {
 39→    /// Fraction of unique branches hit relative to target count (0.0–1.0).
 40→    pub coverage: f64,
 41→    /// Average closeness to flipping target branches (0.0–1.0).
 42→    pub proximity: f64,
 43→    /// Bonus for reaching `SymConstraint::Unknown` branches (0.0–1.0).
 44→    pub unknown_bonus: f64,
 45→    /// 1.0 if this is a novel path, 0.0 if previously seen.
 46→    pub novelty: f64,
 47→    /// Weighted combination of the four components (0.0–1.0).
 48→    pub total: f64,
 49→}
 50→
 51→/// Mutable state tracking previously seen path hashes for novelty scoring.
 52→#[derive(Debug, Clone, Default)]
 53→pub struct FitnessContext {
 54→    seen_paths: HashSet<u64>,
 55→}
 56→
 57→impl FitnessContext {
 58→    pub fn new() -> Self {
 59→        Self::default()
 60→    }
 61→}
 62→
 63→/// Score an execution result against a set of target (uncovered) branch IDs.
 64→///
 65→/// Returns a [`FitnessBreakdown`] with individual component scores and the
 66→/// weighted total, all normalized to 0.0–1.0.
 67→pub fn score(
 68→    result: &ExecuteResult,
 69→    target_branches: &HashSet<u32>,
 70→    context: &mut FitnessContext,
 71→    weights: &FitnessWeights,
 72→) -> FitnessBreakdown {
 73→    let coverage = coverage_score(&result.branch_path, target_branches.len());
 74→    let proximity = proximity_score(&result.branch_path, target_branches);
 75→    let unknown = unknown_bonus_score(&result.branch_path);
 76→    let novelty = novelty_score(&result.branch_path, context);
 77→
 78→    let weight_sum = weights.coverage + weights.proximity + weights.unknown_bonus + weights.novelty;
 79→    let total = if weight_sum > 0.0 {
 80→        (weights.coverage * coverage
 81→            + weights.proximity * proximity
 82→            + weights.unknown_bonus * unknown
 83→            + weights.novelty * novelty)
 84→            / weight_sum
 85→    } else {
 86→        0.0
 87→    };
 88→
 89→    FitnessBreakdown {
 90→        coverage,
 91→        proximity,
 92→        unknown_bonus: unknown,
 93→        novelty,
 94→        total,
 95→    }
 96→}
 97→
 98→// ---------------------------------------------------------------------------
 99→// Component scorers
100→// ---------------------------------------------------------------------------
101→
102→/// Fraction of unique branches hit relative to `target_count`.
103→fn coverage_score(branch_path: &[BranchDecision], target_count: usize) -> f64 {
104→    if target_count == 0 {
105→        return 1.0;
106→    }
107→    let unique: HashSet<u32> = branch_path.iter().map(|bd| bd.branch_id).collect();
108→    let ratio = unique.len() as f64 / target_count as f64;
109→    ratio.min(1.0)
110→}
111→
112→/// Average closeness to flipping each target branch.
113→///
114→/// For each target: if reached in the trace, score = 1 − branch_distance.
115→/// If never reached, contributes 0.
116→fn proximity_score(branch_path: &[BranchDecision], targets: &HashSet<u32>) -> f64 {
117→    if targets.is_empty() {
118→        return 1.0;
119→    }
120→    let mut total = 0.0;
121→    for &target_id in targets {
122→        let closest = branch_path
123→            .iter()
124→            .filter(|bd| bd.branch_id == target_id)
125→            .map(|bd| branch_distance(&bd.constraint))
126→            .min_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
127→
128→        if let Some(dist) = closest {
129→            total += 1.0 - dist;
130→        }
131→    }
132→    total / targets.len() as f64
133→}
134→
135→/// Distance for a single branch constraint (0.0 = at target, 1.0 = far away).
136→fn branch_distance(constraint: &SymConstraint) -> f64 {
137→    match constraint {
138→        SymConstraint::Unknown { .. } => 0.5,
139→        SymConstraint::Expr { expr } => expr_distance(expr),
140→    }
141→}
142→
143→/// Distance derived from a symbolic expression.
144→fn expr_distance(expr: &SymExpr) -> f64 {
145→    match expr {
146→        SymExpr::BinOp { op, left, right } => {
147→            match (eval_to_f64(left), eval_to_f64(right)) {
148→                (Some(l), Some(r)) => comparison_distance(*op, l, r),
149→                _ => 0.5, // cannot evaluate — moderate distance
150→            }

  1→//! Canonical JSON serialization and recipe hashing for generator composite IDs.
  2→//!
  3→//! Generators return a human-readable `id` and a JSON `recipe` for replay.
  4→//! Core combines them into a stable composite key: `"{id}@{recipe_hash_prefix}"`.
  5→//! This module provides deterministic JSON canonicalization so the hash is
  6→//! independent of serialization order or whitespace.
  7→
  8→use sha2::{Digest, Sha256};
  9→use unicode_normalization::UnicodeNormalization;
 10→
 11→/// Deterministic JSON serialization: sorted keys, normalized numbers and strings.
 12→///
 13→/// Guarantees: identical logical values always produce identical output bytes,
 14→/// regardless of the key order, whitespace, or number formatting in the input.
 15→pub fn canonicalize_json(value: &serde_json::Value) -> String {
 16→    let mut buf = String::new();
 17→    write_canonical(value, &mut buf);
 18→    buf
 19→}
 20→
 21→/// SHA-256 of the canonical JSON, truncated to 6 hex characters.
 22→pub fn recipe_hash(value: &serde_json::Value) -> String {
 23→    let canonical = canonicalize_json(value);
 24→    let digest = Sha256::digest(canonical.as_bytes());
 25→    hex::encode(&digest[..3])
 26→}
 27→
 28→/// Composite ID: `"{id}@{recipe_hash_prefix}"`.
 29→pub fn composite_id(id: &str, recipe: &serde_json::Value) -> String {
 30→    format!("{}@{}", id, recipe_hash(recipe))
 31→}
 32→
 33→fn write_canonical(value: &serde_json::Value, buf: &mut String) {
 34→    match value {
 35→        serde_json::Value::Null => buf.push_str("null"),
 36→        serde_json::Value::Bool(b) => buf.push_str(if *b { "true" } else { "false" }),
 37→        serde_json::Value::Number(n) => write_canonical_number(n, buf),
 38→        serde_json::Value::String(s) => write_canonical_string(s, buf),
 39→        serde_json::Value::Array(arr) => {
 40→            buf.push('[');
 41→            for (i, item) in arr.iter().enumerate() {
 42→                if i > 0 {
 43→                    buf.push(',');
 44→                }
 45→                write_canonical(item, buf);
 46→            }
 47→            buf.push(']');
 48→        }
 49→        serde_json::Value::Object(map) => {
 50→            let mut keys: Vec<&String> = map.keys().collect();
 51→            keys.sort();
 52→            buf.push('{');
 53→            for (i, key) in keys.iter().enumerate() {
 54→                if i > 0 {
 55→                    buf.push(',');
 56→                }
 57→                write_canonical_string(key, buf);
 58→                buf.push(':');
 59→                write_canonical(&map[*key], buf);
 60→            }
 61→            buf.push('}');
 62→        }
 63→    }
 64→}
 65→
 66→fn write_canonical_number(n: &serde_json::Number, buf: &mut String) {
 67→    if let Some(i) = n.as_i64() {
 68→        buf.push_str(&i.to_string());
 69→    } else if let Some(u) = n.as_u64() {
 70→        buf.push_str(&u.to_string());
 71→    } else if let Some(f) = n.as_f64() {
 72→        let mut ryu_buf = ryu::Buffer::new();
 73→        buf.push_str(ryu_buf.format(f));
 74→    }
 75→}
 76→
 77→fn write_canonical_string(s: &str, buf: &mut String) {
 78→    let normalized: String = s.nfc().collect();
 79→    buf.push('"');
 80→    for ch in normalized.chars() {
 81→        match ch {
 82→            '"' => buf.push_str("\\\""),
 83→            '\\' => buf.push_str("\\\\"),
 84→            '\n' => buf.push_str("\\n"),
 85→            '\r' => buf.push_str("\\r"),
 86→            '\t' => buf.push_str("\\t"),
 87→            c if c < '\u{0020}' => {
 88→                buf.push_str(&format!("\\u{:04x}", c as u32));
 89→            }
 90→            c => buf.push(c),
 91→        }
 92→    }
 93→    buf.push('"');
 94→}
 95→
 96→#[cfg(test)]
 97→mod tests {
 98→    use super::*;
 99→    use serde_json::json;
100→
101→    #[test]
102→    fn null_bool_canonicalize() {
103→        assert_eq!(canonicalize_json(&json!(null)), "null");
104→        assert_eq!(canonicalize_json(&json!(true)), "true");
105→        assert_eq!(canonicalize_json(&json!(false)), "false");
106→    }
107→
108→    #[test]
109→    fn integer_canonicalize() {
110→        assert_eq!(canonicalize_json(&json!(0)), "0");
111→        assert_eq!(canonicalize_json(&json!(42)), "42");
112→        assert_eq!(canonicalize_json(&json!(-1)), "-1");
113→    }
114→
115→    #[test]
116→    fn float_canonicalize() {
117→        assert_eq!(canonicalize_json(&json!(1.5)), "1.5");
118→        assert_eq!(canonicalize_json(&json!(0.0)), "0.0");
119→    }
120→
121→    #[test]
122→    fn string_canonicalize_escapes() {
123→        assert_eq!(canonicalize_json(&json!("hello")), "\"hello\"");
124→        assert_eq!(canonicalize_json(&json!("a\"b")), "\"a\\\"b\"");
125→        assert_eq!(canonicalize_json(&json!("a\nb")), "\"a\\nb\"");
126→    }
127→
128→    #[test]
129→    fn object_keys_sorted() {
130→        let v = json!({"z": 1, "a": 2, "m": 3});
131→        assert_eq!(canonicalize_json(&v), "{\"a\":2,\"m\":3,\"z\":1}");
132→    }
133→
134→    #[test]
135→    fn nested_object_keys_sorted() {
136→        let v = json!({"b": {"z": 1, "a": 2}, "a": 0});
137→        assert_eq!(canonicalize_json(&v), "{\"a\":0,\"b\":{\"a\":2,\"z\":1}}");
138→    }
139→
140→    #[test]
141→    fn array_preserves_order() {
142→        let v = json!([3, 1, 2]);
143→        assert_eq!(canonicalize_json(&v), "[3,1,2]");
144→    }
145→
146→    #[test]
147→    fn key_order_does_not_affect_hash() {
148→        let v1 = json!({"host": "localhost", "port": 5432});
149→        let v2 = json!({"port": 5432, "host": "localhost"});
150→        assert_eq!(recipe_hash(&v1), recipe_hash(&v2));

  1→//! Log level types for controlling output verbosity.
  2→
  3→use std::fmt;
  4→use std::str::FromStr;
  5→
  6→/// Log verbosity level, from least to most verbose.
  7→#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
  8→pub enum LogLevel {
  9→    Error,
 10→    Warn,
 11→    #[default]
 12→    Info,
 13→    Debug,
 14→    Trace,
